async (page) => {
  const acceptedAnswer = page.locator('.answer.accepted-answer');
  await acceptedAnswer.screenshot({ path: 'eval-so-audit.png' });
  const voteElement = acceptedAnswer.locator('.js-vote-count');
  const voteCount = await voteElement.textContent();
  const authorElement = acceptedAnswer.locator('.user-info .user-details a');
  const author = await authorElement.textContent();
  const codeBlocks = await acceptedAnswer.locator('pre').count();
  const answersHeader = page.locator('.answers-header h2');
  const totalAnswersText = await answersHeader.textContent();
  const totalAnswersMatch = totalAnswersText.match(/(\d+)/);
  const totalAnswers = totalAnswersMatch ? parseInt(totalAnswersMatch[1]) : 0;
  return { voteCount: voteCount.trim(), author: author.trim(), codeBlocks, totalAnswers };
}

